      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const membersService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', (req, res) => {
  const { userId, role } = req.body;

  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_INPUT', 'User ID and role are required.');
  }

  const member = membersService.createMember(req.projectId, userId, role);

  if (member.duplicate) {
    return sendError(res, 409, 'DUPLICATE_MEMBER', 'Member already exists for this project.');
  }

  res.status(201).json({ member: member.member });
});

module.exports = router;
